// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package validationimport (	"fmt"	"math"	"github.com/hashicorp/terraform-plugin-sdk/v2/helper/schema")// IntBetween returns a SchemaValidate which tests if the provided values of type int and is between min and max (inclu) IntBetween(min, max int) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(int)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		if v < min || v > max {			errors = append(errors, fmt.Errorf("expected %s to be in the range (%d - %d), got %d", k, min, max, v))			return warnings, errors		}		return warnings, errors	}// IntAtLeast returns a SchemaValidate which tests if the provided value// is of type int and is at least min (inclusive) IntAtLeast(min int) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(int)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		if v < min {			errors = append(errors, fmt.Errorfpected %s to be at least (%d), got %d", k, min, v))			return warnings, errors		return warnings, errors	}}// IntAtMost returns a SchemaValidate which tests if the provided value// is of type int and is at most max (inclusive) IntAtMost(max int) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(int)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		if v > {			errors = append(errors, fmt.Errorf("expected %s to be at most (%d), got %d", k, max, v))			return warnings, errors		}		return warnings, errors	}}// IntDivisibleBy returns a SchemaValidate which tests if the provided value// is of type int and is divisible by a given number IntDivisibleBy(divisor int) schema.SchemaValidate {	return (i interface{}, k string) (warningstring, errors []error) {		v, ok := i.(int) !ok {			errorappend(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		if math.Mod(float64(v), float64(divisor)) != 0 {			errors = append(errors, fmt.Errorf("expected %s to be divisible by %d, got: %v", k, divisor, i))			return warnings, errors		}		return warnings, errors	}}// IntInSlice returns a SchemaValidate which tests if the provided value// is of type int and matches the value of an element in the valid slice IntInSlice(valid []int) schema.SchemaValidate {	return nterface{}, k string) (warnings []string, err[]error) {		v, ok .(int)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		for _, validInt := range valid {			if v == validInt {				return warnings, errors			}		}		errors = append(errors, fmt.Errorf("expected %s to be one of %v, got %d", k, valid, v))		return warnings, errors	}}// IntNotInSlice returns a SchemaValidate which tests if the provided value// is of type int and matches the value of an element in the valid slice IntNotInSlice(valid []int) schema.SchemaValidate {	return (i interface{}, k string) (warnings []string, errors []error) {		v, ok := i.(int)		if !ok {			errors = append(errors, fmt.Errorf("expected type of %s to be integer", k))			return warnings, errors		}		for _, validInt := range valid {			if v == validInt {				errors = append(errors, fmt.Errorf("expected %s to not be one of %v, got %d", k, valid, v))			}		}		return warnings, errors	}}